#include <bits/stdc++.h>
using namespace std;
const int N=1e3+3,mod=1e9+7;
int t,n,m,a[N],f[N][N],c[N],cnt,ans,b[N];
int lowbit(int x){
    return x&(-x);
}
void add(int x,int y){
    if(x>n)
        return;
    c[x]+=y,c[x]%=mod;
    add(x+lowbit(x),y);
}
int sum(int x){
    if(x==0)
        return c[x];
    return (c[x]+sum(x-lowbit(x)))%mod;
}
int main(){
    scanf("%d",&t);
    while(t--){
        cnt++,ans=0;
        scanf("%d%d",&n,&m);
        for(int i=1;i<=n;i++)
            scanf("%d",&a[i]),b[i]=a[i];
        sort(b+1,b+n+1);
        map<int,int> id;
        int num=1;
        a[0]=1;
        for(int i=1;i<=n;i++)
            if(i==1 || b[i]!=b[i-1])
                id[b[i]]=++num;
        for(int i=1;i<=n;i++)
            a[i]=id[a[i]];
        memset(f,0,sizeof(f));
        f[0][0]=1;
        /*for(int i=1;i<=m;i++)
            for(int j=1;j<=n;j++)
                for(int k=0;k<j;k++)
                    if(a[k]<a[j])
                        f[i][j]+=f[i-1][k],f[i][j]%=mod;
        */
        for(int i=1;i<=m;i++){
            memset(c,0,sizeof(c));
            for(int j=1;j<=n;j++)
                add(a[j-1],f[i-1][j-1]),f[i][j]=sum(a[j]-1);
        }
        for(int i=1;i<=n;i++)
            ans+=f[m][i],ans%=mod;
        printf("Case #%d: %d\n",cnt,ans);
    }
    return 0;
}
